class Solution {
    public int findNthDigit(int n) {
        long count = 9;
        int digit = 1;
        long start = 1;
        while (n > count * digit) {
            n -= count * digit;
            digit++;
            count *= 10;
            start *= 10;
        }
        long num = start + (n - 1) / digit;
        int index = (n - 1) % digit;
        return Integer.parseInt(String.valueOf(num).substring(index, index + 1));
    }
}
```
